class _HomeViewTopMenuButton extends ConsumerWidget {
  const _HomeViewTopMenuButton({
    super.key,
    required this.index,
    required this.label,
  });

  final int index;
  final String label;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final selectedIndex = ref.watch(homeViewPageIndexStateProvider);
    return TextButton(
      style: selectedIndex == index
          ? Theme.of(context)
                .extension<StackColors>()!
                .getPrimaryEnabledButtonStyle(context)!
                .copyWith(
                  minimumSize: MaterialStateProperty.all<Size>(
                    const Size(46, 36),
                  ),
                )
          : Theme.of(context)
                .extension<StackColors>()!
                .getSecondaryEnabledButtonStyle(context)!
                .copyWith(
                  minimumSize: MaterialStateProperty.all<Size>(
                    const Size(46, 36),
                  ),
                ),
      onPressed: () async {
        FocusScope.of(context).unfocus();
        if (selectedIndex != index) {
          ref.read(homeViewPageIndexStateProvider.state).state = index;
        }
      },
      child: Padding(
        padding: const .symmetric(horizontal: 8),
        child: Text(
          label,
          style: STextStyles.button(context).copyWith(
            fontSize: 14,
            color: selectedIndex == index
                ? Theme.of(context).extension<StackColors>()!.buttonTextPrimary
                : Theme.of(
                    context,
                  ).extension<StackColors>()!.buttonTextSecondary,
          ),
        ),
      ),
    );
  }
}
